update orders
set status = #{order.status},
cancel_reason = #{order.cancelReason},
cancel_time = #{order.cancelTime}
where id = #{order.id}

mapper.select:
select * from orders



        and number like concat('%',#{number},'%')



        and phone like concat('%',#{phone},'%')



        and user_id = #{userId}



        and status = #{status}



        and order_time >= #{beginTime}



        and order_time <= #{endTime}


order by order_time desc

select DATE(delivery_time) as date, COUNT(*) as value from orders where delivery_time >= #{begin} and delivery_time < #{end} and status in
#{status}
group by DATE(delivery_time) order by date
